var LipsyncStatusesList = &command.Spec{
	Group:          "lipsync",
	Name:           "statuses list",
	Summary:        "Bulk Lipsync Statuses",
	Description:    "Returns statuses for up to 100 lipsyncs in one request, addressed by comma-separated lipsync_ids and/or batch_ids query params. Statuses are one of queued, processing, completed, or failed, plus not_found for unknown or unowned ids. Each returned entry carries its id as video_id (the status read model is shared with the videos batch API).",
	ResponseSchema: "{\n  \"properties\": {\n    \"data\": {\n      \"items\": {\n        \"properties\": {\n          \"batch_id\": {\n            \"description\": \"Set for entries expanded from a batch_id.\",\n            \"nullable\": true,\n            \"type\": \"string\"\n          },\n          \"error\": {\n            \"description\": \"Failure details when status is failed.\",\n            \"nullable\": true,\n            \"properties\": {},\n            \"required\": [],\n            \"type\": \"object\"\n          },\n          \"item_index\": {\n            \"description\": \"Set for entries expanded from a batch_id, to correlate items without a video_id yet.\",\n            \"nullable\": true,\n            \"type\": \"integer\"\n          },\n          \"status\": {\n            \"description\": \"Video status (same values as GET /v1/video_status.get), or not_found for unknown/unowned ids.\",\n            \"type\": \"string\"\n          },\n          \"video_id\": {\n            \"description\": \"Video id. Null for batch items whose video has not been created yet.\",\n            \"nullable\": true,\n            \"type\": \"string\"\n          }\n        },\n        \"required\": [\n          \"status\"\n        ],\n        \"type\": \"object\"\n      },\n      \"type\": \"array\"\n    },\n    \"has_more\": {\n      \"description\": \"Whether more pages are available\",\n      \"type\": \"boolean\"\n    },\n    \"next_token\": {\n      \"description\": \"Opaque cursor for the next page\",\n      \"nullable\": true,\n      \"type\": \"string\"\n    }\n  },\n  \"required\": [],\n  \"type\": \"object\"\n}",
	Endpoint:       "/v3/lipsyncs/statuses",
	Method:         "GET",
	BodyEncoding:   "",
	Examples: []string{
		"# Look up statuses for specific lipsync ids\n  heygen lipsync statuses list --lipsync-ids <lipsync-id-1>,<lipsync-id-2>",
		"# Expand batches into their member lipsync statuses\n  heygen lipsync statuses list --batch-ids <batch-id-1>,<batch-id-2>",
	},
	Flags: []command.FlagSpec{
		{
			Name:     "lipsync-ids",
			Type:     "string",
			Default:  "",
			Help:     "Comma-separated lipsync ids to look up.",
			Required: false,
			Enum:     nil,
			Min:      nil,
			Max:      nil,
			Source:   "query",
			JSONName: "lipsync_ids",
		},
		{
			Name:     "batch-ids",
			Type:     "string",
			Default:  "",
			Help:     "Comma-separated batch ids; each expands to its member lipsyncs.",
			Required: false,
			Enum:     nil,
			Min:      nil,
			Max:      nil,
			Source:   "query",
			JSONName: "batch_ids",
		},
	},
}

